#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Monitor a job run and fetch output
 *
 * This example demonstrates:
 * - Getting the status of a running or completed job
 * - Fetching task output
 * - Handling different run states
 * - Getting execution details
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 * - An existing run ID (set TEST_RUN_ID environment variable)
 *
 * Usage:
 *   export TEST_RUN_ID="your-run-id"
 *   npx ts-node examples/workspace/jobs/monitor-job-run.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const runId = process.env.TEST_RUN_ID;

    if (!runId) {
        console.error("✗ Error: TEST_RUN_ID environment variable not set");
        console.error("  Please set it to an existing run ID.");
        process.exit(1);
    }

    console.log(`Monitoring job run: ${runId}\n`);

    try {
        // Get run details
        const run = await client.jobs.getRun({run_id: parseInt(runId)});

        console.log(`Job Name: ${run.run_name || "(unnamed)"}`);
        console.log(`Run ID: ${run.run_id}`);
        console.log(`Job ID: ${run.job_id}`);
        console.log(`Life Cycle State: ${run.state?.life_cycle_state}`);
        console.log(`Result State: ${run.state?.result_state || "N/A"}`);

        if (run.state?.state_message) {
            console.log(`Message: ${run.state.state_message}`);
        }

        console.log(
            `\nRun URL: ${client.config.host}#job/${run.job_id}/run/${run.run_id}`
        );

        // Display task information
        if (run.tasks && run.tasks.length > 0) {
            console.log(`\nTasks (${run.tasks.length}):`);

            const tasks = run.tasks.map((task) => ({
                "Task Key": task.task_key,
                "State": task.state?.life_cycle_state,
                "Result": task.state?.result_state || "N/A",
                "Started": task.start_time
                    ? new Date(task.start_time).toISOString()
                    : "N/A",
                "Ended": task.end_time
                    ? new Date(task.end_time).toISOString()
                    : "N/A",
                "Duration (s)":
                    task.start_time && task.end_time
                        ? ((task.end_time - task.start_time) / 1000).toFixed(2)
                        : "N/A",
            }));

            console.table(tasks);
        }

        // Display cluster information
        if (run.cluster_instance) {
            console.log(`\nCluster:`);
            console.log(`  Cluster ID: ${run.cluster_instance.cluster_id}`);
            console.log(
                `  Spark Context ID: ${run.cluster_instance.spark_context_id || "N/A"}`
            );
        }

        // Check final status
        console.log(`\nFinal Status:`);
        if (
            run.state?.life_cycle_state === "TERMINATED" ||
            run.state?.life_cycle_state === "INTERNAL_ERROR"
        ) {
            if (run.state.result_state === "SUCCESS") {
                console.log(`  ✓ Job completed successfully`);
            } else if (run.state.result_state === "FAILED") {
                console.log(`  ✗ Job failed`);
            } else if (run.state.result_state === "CANCELED") {
                console.log(`  ⊘ Job was canceled`);
            } else {
                console.log(
                    `  ? Job ended with state: ${run.state.result_state}`
                );
            }
        } else {
            console.log(
                `  ⏳ Job is still running (${run.state?.life_cycle_state})`
            );
        }
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
